examples.code:
#include <print>

int main() {
    int x;             // automatic storage — no initializer
    int y = x + 1;    // erroneous behavior: x has an unspecified value
    std::print("y = {}\n", y);
}

#include <print>

struct Point {
    int x;
    int y;
    // no default member initializers — when constructed without
    // an initializer list, both fields are indeterminate
};

int main() {
    Point p;                    // p.x and p.y are uninitialized
    p.x = 10;                   // x is now initialized
    int result = p.x + p.y;    // erroneous behavior: p.y is unspecified
    std::print("result = {}\n", result);
}

#include <print>

void fill_buffer(char* buf, int n) {
    for (int i = 0; i < n; ++i)
        buf[i] = static_cast<char>('A' + i % 26);
}

int main() {
    char buf[[indeterminate]] [8];  // explicitly opt out of EB diagnostics
    fill_buffer(buf, 8);           // buffer is fully filled before any read
    buf[7] = '\0';
    std::print("{}\n", buf);
}

