examples.code:
#include <print>

// Before C++26: a loop with no observable side effects was UB.
// The compiler could assume it terminates and move code around it.
// C++26: a trivially-empty infinite loop is explicitly defined to
// spin forever — the compiler may not delete or hoist past it.

volatile bool ready = true; // volatile: the read is an observable effect

int main() {
    // C++26: well-formed — compiler cannot delete this loop
    while (!ready) {} // spin until ready is set

    std::print("ready\n");
    std::print("spin loops are defined in C++26\n");
}

#include <print>

// P0963: structured binding declaration as the condition in if.
// The bound object serves as the condition via contextual bool conversion.

struct Lookup {
    bool found;
    int  value;
    explicit operator bool() const { return found; }
};

Lookup search(int key) {
    if (key > 0) return {true, key * 10};
    return {false, 0};
}

int main() {
    // C++26: declare and test in one expression.
    // found and value are accessible in both branches but not outside.
    if (auto [found, value] = search(5)) {
        std::print("found={} value={}\n", found, value);
    }

    if (auto [found, value] = search(-1)) {
        std::print("should not print\n");
    } else {
        std::print("not found, value={}\n", value);
    }
}

